<?php require_once __DIR__.'/../../middleware/bootstrap.php';$d=array_map('clean',input());if(!filter_var($d['email']??'',FILTER_VALIDATE_EMAIL)||strlen($d['password']??'')<8)out(['error'=>'Invalid registration'],422);$pdo=db();$pdo->beginTransaction();$st=$pdo->prepare('insert into users(name,email,password_hash,verification_token,status,created_at)values(?,?,?,?,"active",now())');$st->execute([$d['name']??'Customer',$d['email'],password_hash($d['password'],PASSWORD_DEFAULT),bin2hex(random_bytes(16))]);$uid=$pdo->lastInsertId();$pdo->prepare('insert into wallets(user_id,balance,promo_balance,currency,created_at)values(?,0,0,"USD",now())')->execute([$uid]);$pdo->commit();out(['token'=>jwt($uid),'user'=>['id'=>$uid,'email'=>$d['email'],'name'=>$d['name']??'Customer']]);
